diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 0633388cd411..069b3714dee4 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3131,6 +3131,25 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
         return &SI;
       }
     }
+    // select(select(C0, true, C1), select(!C0, true, Y), B) -> select(C0, Y, select(C1, true, B))
+    // This handles the OR case where true value's select condition is negation of outer's first operand.
+    if (auto *CondSI = dyn_cast<SelectInst>(CondVal)) {
+      Value *NotTrueSICond;
+      if (match(TrueSI->getCondition(), m_Not(m_Value(NotTrueSICond))) &&
+          NotTrueSICond == CondSI->getCondition() &&
+          match(CondSI->getTrueValue(), m_One()) &&
+          match(TrueSI->getTrueValue(), m_One())) {
+        if (TrueSI->hasOneUse()) {
+          Value *C0 = CondSI->getCondition();
+          Value *C1 = CondSI->getFalseValue();
+          Value *NewFalse = Builder.CreateSelect(C1, ConstantInt::getTrue(SelType), FalseVal);
+          replaceOperand(SI, 0, C0);
+          replaceOperand(SI, 1, TrueSI->getFalseValue());
+          replaceOperand(SI, 2, NewFalse);
+          return &SI;
+        }
+      }
+    }
   }
   if (SelectInst *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
     if (FalseSI->getCondition()->getType() == CondVal->getType()) {
@@ -3148,6 +3167,87 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
         return &SI;
       }
     }
+    // select(select(C0, C1, false), A, select(C0, X, Y)) -> select(C0, select(C1, A, X), Y)
+    // This transforms (C0 AND C1) ? A : (C0 ? X : Y) into C0 ? (C1 ? A : X) : Y
+    if (auto *CondSI = dyn_cast<SelectInst>(CondVal)) {
+      if (CondSI->getCondition() == FalseSI->getCondition() &&
+          match(CondSI->getFalseValue(), m_Zero())) {
+        if (FalseSI->hasOneUse()) {
+          Value *NewTrue = Builder.CreateSelect(CondSI->getTrueValue(), TrueVal,
+                                                FalseSI->getTrueValue());
+          replaceOperand(SI, 0, CondSI->getCondition());
+          replaceOperand(SI, 1, NewTrue);
+          replaceOperand(SI, 2, FalseSI->getFalseValue());
+          return &SI;
+        }
+      }
+    }
+    // select(and(C0, C1), A, select(C0, X, Y)) -> select(C0, select(C1, A, X), Y)
+    // This handles the case where select(C0, C1, false) was folded to and(C0, C1).
+    if (auto *CondAnd = dyn_cast<BinaryOperator>(CondVal)) {
+      if (CondAnd->getOpcode() == Instruction::And &&
+          CondAnd->getOperand(0) == FalseSI->getCondition()) {
+        if (FalseSI->hasOneUse()) {
+          Value *C0 = FalseSI->getCondition();
+          Value *C1 = CondAnd->getOperand(1);
+          Value *NewTrue = Builder.CreateSelect(C1, TrueVal, FalseSI->getTrueValue());
+          replaceOperand(SI, 0, C0);
+          replaceOperand(SI, 1, NewTrue);
+          replaceOperand(SI, 2, FalseSI->getFalseValue());
+          return &SI;
+        }
+      } else if (CondAnd->getOpcode() == Instruction::And &&
+                 CondAnd->getOperand(1) == FalseSI->getCondition()) {
+        // Handle commutative case: and(C1, C0)
+        if (FalseSI->hasOneUse()) {
+          Value *C0 = FalseSI->getCondition();
+          Value *C1 = CondAnd->getOperand(0);
+          Value *NewTrue = Builder.CreateSelect(C1, TrueVal, FalseSI->getTrueValue());
+          replaceOperand(SI, 0, C0);
+          replaceOperand(SI, 1, NewTrue);
+          replaceOperand(SI, 2, FalseSI->getFalseValue());
+          return &SI;
+        }
+      }
+    }
+    // select(select(C0, C1, false), A, select(!C0, Y, false)) -> select(C0, select(C1, A, false), Y)
+    // This handles the case where inner select's condition is negation of outer's first operand.
+    if (auto *CondSI = dyn_cast<SelectInst>(CondVal)) {
+      Value *NotFalseSICond;
+      if (match(FalseSI->getCondition(), m_Not(m_Value(NotFalseSICond))) &&
+          NotFalseSICond == CondSI->getCondition() &&
+          match(CondSI->getFalseValue(), m_Zero()) &&
+          match(FalseSI->getFalseValue(), m_Zero())) {
+        if (FalseSI->hasOneUse()) {
+          Value *C0 = CondSI->getCondition();
+          Value *C1 = CondSI->getTrueValue();
+          Value *NewTrue = Builder.CreateSelect(C1, TrueVal, ConstantInt::getFalse(SelType));
+          replaceOperand(SI, 0, C0);
+          replaceOperand(SI, 1, NewTrue);
+          replaceOperand(SI, 2, FalseSI->getTrueValue());
+          return &SI;
+        }
+      }
+    }
+    // select(select(C0, true, C1), select(!C0, true, Y), B) -> select(C0, Y, select(C1, true, B))
+    // This handles the OR case where inner select's condition is negation of outer's first operand.
+    if (auto *CondSI = dyn_cast<SelectInst>(CondVal)) {
+      Value *NotFalseSICond;
+      if (match(FalseSI->getCondition(), m_Not(m_Value(NotFalseSICond))) &&
+          NotFalseSICond == CondSI->getCondition() &&
+          match(CondSI->getTrueValue(), m_One()) &&
+          match(FalseSI->getTrueValue(), m_One())) {
+        if (FalseSI->hasOneUse()) {
+          Value *C0 = CondSI->getCondition();
+          Value *C1 = CondSI->getFalseValue();
+          Value *NewFalse = Builder.CreateSelect(C1, ConstantInt::getTrue(SelType), FalseVal);
+          replaceOperand(SI, 0, C0);
+          replaceOperand(SI, 1, FalseSI->getFalseValue());
+          replaceOperand(SI, 2, NewFalse);
+          return &SI;
+        }
+      }
+    }
   }

