  2060 |     if (Elt->isOneValue()) {
  2061 |       // If the select condition element is true, choose from the 1st vector.
  2062 |       Mask.push_back(i);
  2063 |     } else if (Elt->isNullValue()) {
  2064 |       // If the select condition element is false, choose from the 2nd vector.
  2065 |       Mask.push_back(i + NumElts);
